from pydantic_ai import Agent
from pydantic import ValidationError

class ContextOverflowDetector:
    def __init__(self, agent: Agent):
        self.agent = agent
        self.truncation_errors = 0

    def run_with_monitoring(self, messages):
        try:
            return self.agent.run(messages)
        except ValidationError as e:
            if 'truncated' in str(e).lower() or 'unexpected end' in str(e).lower():
                self.truncation_errors += 1
            raise

# Usage
detector = ContextOverflowDetector(agent)
result = detector.run_with_monitoring(messages)

