from pydantic_ai import Agent

class SmartRetryAgent:
    def __init__(self, base_agent: Agent, max_retries: int = 3):
        self.agent = base_agent
        self.max_retries = max_retries

    def run(self, messages: list, retry_context: bool = True):
        for attempt in range(self.max_retries):
            try:
                return self.agent.run(messages)
            except Exception:
                if retry_context and attempt < self.max_retries - 1:
                    # Reset to last known good context
                    messages = messages[-3:]  # Keep last 3 messages
        raise

# Usage
smart_agent = SmartRetryAgent(agent)
result = smart_agent.run(messages)
